const prev   = $('Store Email').first().json;
const calRaw = $json;

let events = [];
try {
  const raw     = calRaw?.choices?.[0]?.message?.content || '[]';
  const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```\s*$/i,'').trim();
  const parsed  = JSON.parse(cleaned);
  events        = Array.isArray(parsed) ? parsed.filter(e => e.title && e.dayOffset && e.startHour) : [];
} catch(e) { events = []; }

if (!events.length) {
  events = [
    { title: 'Week ' + prev.weekNum + ' Study Session', description: 'Review material', dayOffset: 2, startHour: 18, durationMinutes: 90, colorId: '7' },
    { title: 'Week ' + prev.weekNum + ' Review Block',  description: 'Practice problems', dayOffset: 4, startHour: 19, durationMinutes: 60, colorId: '9' }
  ];
}

const TZ = 'Asia/Kolkata'; // Change to your timezone
const calEvents = events.map(ev => {
  const start = new Date();
  start.setDate(start.getDate() + Math.max(1, parseInt(ev.dayOffset) || 1));
  start.setHours(Math.min(22, Math.max(6, parseInt(ev.startHour) || 18)), 0, 0, 0);
  const end = new Date(start.getTime() + Math.max(30, parseInt(ev.durationMinutes) || 90) * 60000);
  return {
    summary:     String(ev.title || 'Study Session').slice(0, 100),
    description: String(ev.description || '').slice(0, 500),
    colorId:     String(ev.colorId || '7'),
    start: { dateTime: start.toISOString(), timeZone: TZ },
    end:   { dateTime: end.toISOString(),   timeZone: TZ }
  };
});

return [{ json: {
  emailBody:    prev.emailBody,
  calEvents,
  studentEmail: prev.studentEmail,
  courseName:   prev.courseName,
  weekNum:      prev.weekNum,
  subject:      '📚 Week ' + prev.weekNum + ' Study Prep — ' + prev.courseName
}}];
